mapper.select:
SELECT sur.* FROM sys_user_rank sur
WHERE sur.user_id = #{userId}

    AND EXISTS (select sr.id from sys_rank sr where sr.id = sur.rank_id and sr.org_id = #{orgId})

SELECT sr.rank_name
FROM sys_rank sr
         JOIN sys_user_rank sur ON sr.id = sur.rank_id AND sur.user_id = #{userId}
WHERE sr.org_id = #{orgId}
